<?php declare(strict_types=1); namespace App\Filament\Tenant\Resources\Confectionery; use App\Domains\Confectionery\Models\Confectionery; use App\Filament\Tenant\Resources\ConfectioneryResource\Pages; use Filament\Forms\Components\TextInput; use Filament\Forms\Components\Select; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables\Columns\TextColumn; use Filament\Tables\Table; final class ConfectioneryResource extends Resource { protected static ?string $model = Confectionery::class; protected static ?string $navigationIcon = 'heroicon-o-cake'; protected static ?string $navigationGroup = 'Food'; public static function form(Form $form): Form { return $form->schema([TextInput::make('name')->required()->maxLength(255), TextInput::make('sku')->required()->unique()->maxLength(50), Select::make('category')->required()->options(['cake' => 'Cake', 'pastry' => 'Pastry', 'chocolate' => 'Chocolate', 'candy' => 'Candy', 'cookie' => 'Cookie', 'donut' => 'Donut']), TextInput::make('price')->numeric()->required(), TextInput::make('current_stock')->numeric()->required(), TextInput::make('rating')->numeric()->step(0.1), TextInput::make('review_count')->numeric(),]); } public static function table(Table $table): Table { return $table->columns([TextColumn::make('name')->sortable()->searchable(), TextColumn::make('sku')->sortable(), TextColumn::make('category'), TextColumn::make('price')->formatStateUsing(fn($state) => $state . ' ₽'), TextColumn::make('current_stock'), TextColumn::make('rating')->sortable(),])->filters([])->actions([\Filament\Tables\Actions\EditAction::make(),])->bulkActions([\Filament\Tables\Actions\BulkActionGroup::make([\Filament\Tables\Actions\DeleteBulkAction::make(),]),]); } public static function getPages(): array { return ['index' => Pages\ListConfectioneries::route('/'), 'create' => Pages\CreateConfectioneries::route('/create'), 'edit' => Pages\EditConfectioneries::route('/{record}/edit'),]; } }
